import pytest
from app.ai.conversation_memory import phone_shared_state

class DummyConversation:
    def __init__(self, phone_number_shared_at=None):
        self.phone_number_shared_at = phone_number_shared_at

def make_message(sender=None, direction=None, text=""):
    msg = {}
    if sender is not None:
        msg["sender"] = sender
    if direction is not None:
        msg["direction"] = direction
    msg["text"] = text
    return msg

def test_returns_true_if_conversation_phone_number_shared_at_truthy():
    conversation = DummyConversation(phone_number_shared_at="2024-01-01T00:00:00Z")
    persona = {"mobile_number": "07911123456"}
    messages = []
    assert phone_shared_state(messages, persona, conversation) is True

def test_returns_false_if_persona_has_no_mobile_number():
    conversation = DummyConversation(phone_number_shared_at=None)
    persona = {}
    messages = [
        make_message(sender="user", text="My number is 07911123456"),
    ]
    assert phone_shared_state(messages, persona, conversation) is False

@pytest.mark.parametrize("sender_key", ["sender", "direction"])
@pytest.mark.parametrize("sender_value", ["User", "Tenant", "Outbound", "AI", "user", "tenant", "outbound", "ai"])
def test_detects_number_in_tenant_side_messages_with_sender_and_direction(sender_key, sender_value):
    conversation = DummyConversation(phone_number_shared_at=None)
    persona = {"mobile_number": "07911123456"}
    msg = {"text": "Call me at 07911 123 456"}
    msg[sender_key] = sender_value
    messages = [msg]
    # Only tenant-side senders count
    tenant_side = sender_value.lower() in {"user", "tenant", "outbound", "ai"}
    expected = tenant_side
    assert phone_shared_state(messages, persona, conversation) is expected

def test_number_matching_ignores_non_digits_and_matches_local_and_international_forms():
    conversation = DummyConversation(phone_number_shared_at=None)
    persona = {"mobile_number": "07911123456"}
    messages = [
        make_message(sender="user", text="My number is 07911 123 456"),  # local form with spaces
        make_message(sender="tenant", text="Call me on +44 7911 123456"),  # international with plus and space
        make_message(sender="ai", text="Reach me at 447911123456"),  # international without plus
    ]
    # Should return True because at least one message contains the number in tenant-side message
    assert phone_shared_state(messages, persona, conversation) is True

def test_returns_false_if_number_not_in_any_tenant_side_message():
    conversation = DummyConversation(phone_number_shared_at=None)
    persona = {"mobile_number": "07911123456"}
    messages = [
        make_message(sender="agent", text="My number is 07911123456"),  # sender not tenant-side
        make_message(sender="system", text="07911123456"),  # sender not tenant-side
        make_message(direction="inbound", text="07911123456"),  # direction not tenant-side
    ]
    assert phone_shared_state(messages, persona, conversation) is False

def test_case_insensitive_sender_key_and_value_handling():
    conversation = DummyConversation(phone_number_shared_at=None)
    persona = {"mobile_number": "07911123456"}
    messages = [
        {"Sender": "User", "Text": "My number is 07911123456"},  # keys not lowercase, should fallback to "direction" key
        {"sender": "USER", "text": "Call me 07911123456"},  # uppercase sender value
        {"direction": "Tenant", "text": "07911123456"},  # direction key with mixed case
    ]
    # Only the second and third messages count because first has no "sender" or "direction" lowercase keys
    # But spec says fallback to "direction" key if "sender" missing, so first message has no "sender" or "direction" lowercase keys, so ignored
    # Second and third messages have tenant-side sender/direction (case-insensitive)
    # So overall should return True
    assert phone_shared_state(messages, persona, conversation) is True

