from app.ai.stages import detect_stage
from app.db.status import VIEWING_DISCUSSION, VIEWING_BOOKED
import pytest

def test_empty_and_none_input_returns_none():
    assert detect_stage([]) is None
    assert detect_stage(None) is None

def test_only_most_recent_8_messages_considered():
    # 9 messages, first contains booking confirmation + time but should be ignored
    messages = [
        {"message": "Confirmed, see you Thursday at 2pm", "sender": "landlord"},
    ] + [{"message": "irrelevant message", "sender": "tenant"}]*8
    # Only last 8 messages considered, none contain booking info
    assert detect_stage(messages) is None

    # Now put booking info in last 8 messages
    messages = [{"message": "irrelevant", "sender": "tenant"}]*1 + [
        {"message": "Confirmed, see you Thursday at 2pm", "sender": "landlord"},
    ] + [{"message": "irrelevant", "sender": "tenant"}]*6
    # Last 8 messages include booking info, so should detect booked
    assert detect_stage(messages) == VIEWING_BOOKED

def test_negation_keywords_mid_sentence_return_viewing_discussion():
    messages = [
        {"message": "I think we need to reschedule the viewing to another time", "sender": "tenant"},
    ]
    assert detect_stage(messages) == VIEWING_DISCUSSION

    messages = [
        {"message": "Can we rearrange the appointment? I need to change plans.", "sender": "landlord"},
    ]
    assert detect_stage(messages) == VIEWING_DISCUSSION

def test_booking_confirmation_and_time_in_different_messages_returns_viewing_booked():
    messages = [
        {"message": "Confirmed, I'll see you then", "sender": "landlord"},
        {"message": "Saturday at 2pm", "sender": "tenant"},
    ]
    assert detect_stage(messages) == VIEWING_BOOKED

def test_booking_confirmation_and_time_in_same_message_returns_viewing_booked():
    messages = [
        {"message": "Confirmed, see you Thursday at 14:30", "sender": "landlord"},
    ]
    assert detect_stage(messages) == VIEWING_BOOKED

def test_scheduling_discussion_without_booking_returns_viewing_discussion():
    messages = [
        {"message": "Are you available next Wednesday?", "sender": "tenant"},
        {"message": "I can do Thursday or Friday afternoon", "sender": "landlord"},
    ]
    assert detect_stage(messages) == VIEWING_DISCUSSION

def test_fallback_keys_message_and_sender_used():
    messages = [
        {"content": "I think we need to reschedule", "direction": "tenant"},
    ]
    assert detect_stage(messages) == VIEWING_DISCUSSION
